class Playground {
    async run(inputs) {
        const mat = JSON.parse(inputs[0]);
        const m = mat.length;
        const n = mat[0].length;

        // 1. Initialize data structures
        await this.grid.init(mat);
        await this.rowSums.init(new Array(m).fill(0));
        await this.colSums.init(new Array(n).fill(0));
        await this.vars.init([["Special Count", 0]]);

        this.log("Step 1: Counting 1s in each row and column.");
        await this.await();

        // 2. Pre-calculate row and column sums
        for (let r = 0; r < m; r++) {
            for (let c = 0; c < n; c++) {
                const val = this.grid.getCell(r, c);
                this.grid.highlight(r, c, "#00e0ff"); // Current scan color

                if (val === 1) {
                    const current_row_val = this.rowSums.get(r);
                    const current_col_val = this.colSums.get(c);

                    this.rowSums.set(r, current_row_val + 1);
                    this.colSums.set(c, current_col_val + 1);

                    this.rowSums.highlight(r, "#00f5a0");
                    this.colSums.highlight(c, "#00f5a0");

                    this.log(`Found 1 at [${r}, ${c}]. Incrementing row ${r} and column ${c} counts.`);
                    await this.await();

                    this.rowSums.highlight(r, null);
                    this.colSums.highlight(c, null);
                }
                this.grid.highlight(r, c, null);
            }
        }

        this.log("Step 2: Identifying special positions based on counts.");
        let count = 0;
        await this.await();

        // 3. Identify special positions
        for (let r = 0; r < m; r++) {
            for (let c = 0; c < n; c++) {
                this.grid.highlight(r, c, "#ffb703"); // Inspection color
                const val = this.grid.getCell(r, c);

                if (val === 1) {
                    const rCount = this.rowSums.get(r);
                    const cCount = this.colSums.get(c);

                    if (rCount === 1 && cCount === 1) {
                        count++;
                        this.vars.put("Special Count", count);
                        this.grid.highlight(r, c, "#00f5a0"); // Success color
                        this.log(`Position [${r}, ${c}] is special! (Row ${r} sum: 1, Col ${c} sum: 1)`);
                        await this.await();
                    } else {
                        this.log(`Position [${r}, ${c}] is NOT special. (Row sum: ${rCount}, Col sum: ${cCount})`);
                        await this.await();
                        this.grid.highlight(r, c, null);
                    }
                } else {
                    this.grid.highlight(r, c, null);
                }
            }
        }

        this.log(`Finished. Total special positions: ${count}`);
        return count;
    }
}
